// Breathe GPIO2 with PWM. Watch the pin pulse in the simulator,
// or wire GPIO2 -> 220R -> LED -> GND for the real thing.

fn on_start() {
    this.t = 0.0;
    log("breathing GPIO2 at 1 kHz PWM");
}

fn on_tick(dt_ms) {
    this.t += dt_ms.to_float() / 2000.0;      // one breath every ~2 s
    let s = (this.t * 3.141592).sin().abs();
    let duty = (s * s * 1000.0).to_int();     // squared for a natural fade
    pin(2).pwm(1000, duty);
}
